import"./ticker-BxUDbM2L.js";import{i as a}from"./country-page-CK6BdUjw.js";import"./utils-Owvk3OYq.js";import"./breadcrumbs-CxxVGuAV.js";a({countryCode:"QA",currency:"QAR",flag:"🇶🇦",nameEn:"Qatar",nameAr:"قطر",fixedPeg:!1,decimals:2,timezone:"Asia/Qatar",relatedCountries:[{file:"uae.html",nameEn:"UAE",nameAr:"الإمارات",flag:"🇦🇪"},{file:"saudi-arabia.html",nameEn:"Saudi Arabia",nameAr:"السعودية",flag:"🇸🇦"},{file:"kuwait.html",nameEn:"Kuwait",nameAr:"الكويت",flag:"🇰🇼"},{file:"bahrain.html",nameEn:"Bahrain",nameAr:"البحرين",flag:"🇧🇭"},{file:"oman.html",nameEn:"Oman",nameAr:"عُمان",flag:"🇴🇲"},{file:"egypt.html",nameEn:"Egypt",nameAr:"مصر",flag:"🇪🇬"}],faqEn:[{q:"What is today's gold price in Qatar?",a:"The Qatari Riyal (QAR) is pegged to the US Dollar at a fixed rate of 3.64 QAR per USD, making gold prices in Qatar extremely stable and directly tied to global XAU/USD movements. Prices on this page are updated every 90 seconds."},{q:"Where can I buy gold in Qatar?",a:"Souq Waqif in central Doha is the most famous destination for gold shopping in Qatar, offering a traditional market experience. Large shopping malls such as Villaggio Mall and City Center Doha also host many reputable jewellers."},{q:"Is there tax on gold in Qatar?",a:"Qatar has no Value Added Tax (VAT) and no personal income tax, making the purchase of gold straightforward with no additional tax burden on buyers. The price you see is essentially what you pay, plus any jeweller's making charges."},{q:"What karats are popular in Qatar?",a:"22K and 21K gold are the most common choices for jewellery in Qatar. 24K gold bars and coins are popular for investment, while 18K is used for intricate modern jewellery designs."}],faqAr:[{q:"ما هو سعر الذهب اليوم في قطر؟",a:"يرتبط الريال القطري (QAR) بالدولار الأمريكي بسعر صرف ثابت قدره 3.64 ريال لكل دولار، مما يجعل أسعار الذهب في قطر مستقرةً للغاية ومرتبطةً مباشرةً بتحركات XAU/USD العالمية. يتم تحديث الأسعار في هذه الصفحة كل 90 ثانية."},{q:"أين يمكنني شراء الذهب في قطر؟",a:"يُعدّ سوق واقف في وسط الدوحة الوجهة الأشهر لشراء الذهب في قطر، إذ يوفر تجربة السوق التقليدية. كما تضم المراكز التجارية الكبرى كفيلاجيو مول وسيتي سنتر الدوحة عدداً كبيراً من تجار المجوهرات المعتمدين."},{q:"هل يُفرض ضريبة على الذهب في قطر؟",a:"لا تفرض قطر ضريبة القيمة المضافة (VAT) ولا ضريبة دخل شخصية، مما يجعل شراء الذهب خاليًا من أي أعباء ضريبية إضافية على المشترين. السعر الذي تراه هو ما تدفعه فعلاً، مضافاً إليه أجور الصياغة لدى الصائغ."},{q:"ما هي العيارات الأكثر شيوعاً في قطر؟",a:"يُعدّ عيار 22 وعيار 21 الأكثر شيوعاً للمجوهرات في قطر. أما سبائك وعملات عيار 24 فهي شائعة للأغراض الاستثمارية، فيما يُستخدم عيار 18 لتصاميم المجوهرات الحديثة الدقيقة."}]});
